&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;&lt;td&gt;NHTSA (nhtsa.gov)&lt;/td&gt;&lt;td&gt;Free&lt;/td&gt;&lt;td&gt;No&lt;/td&gt;&lt;td&gt;No&lt;/td&gt;&lt;td&gt;No&lt;/td&gt;&lt;td&gt;No&lt;/td&gt;&lt;td&gt;Yes&lt;/td&gt;&lt;td&gt;No&lt;/td&gt;&lt;/tr&gt;
&lt;tr&gt;&lt;td&gt;NICB VINCheck&lt;/td&gt;&lt;td&gt;Free&lt;/td&gt;&lt;td&gt;No&lt;/td&gt;&lt;td&gt;Total-loss only&lt;/td&gt;&lt;td&gt;Yes&lt;/td&gt;&lt;td&gt;No&lt;/td&gt;&lt;td&gt;No&lt;/td&gt;&lt;td&gt;No&lt;/td&gt;&lt;/tr&gt;
